function useInView(threshold = 0.12) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) { setVisible(true); obs.unobserve(el); } },
      { threshold }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, []);
  return [ref, visible];
}

function FadeIn({ children, delay = 0, className = "", style = {} }) {
  const [ref, visible] = useInView();
  return (
    <div
      ref={ref}
      className={className}
      style={{
        ...style,
        opacity: visible ? 1 : 0,
        transform: visible ? "translateY(0)" : "translateY(28px)",
        transition: `opacity 0.75s cubic-bezier(.22,1,.36,1) ${delay}s, transform 0.75s cubic-bezier(.22,1,.36,1) ${delay}s`,
      }}
    >
      {children}
    </div>
  );
}

function NewsletterForm() {
  const [formData, setFormData] = useState({
    fullName: "",
    email: "",
    phone: ""
  });
  const [status, setStatus] = useState("idle"); // idle, loading, success, error
  const [errorMessage, setErrorMessage] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setStatus("loading");
    setErrorMessage("");

    // Validate phone number format
    const phoneDigits = formData.phone.replace(/\D/g, '');
    if (phoneDigits.length < 10) {
      setStatus("error");
      setErrorMessage("Please enter a valid phone number with country code (e.g., +14081234567)");
      return;
    }

    try {
      const response = await fetch("/api/newsletter", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(formData),
      });

      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.message || "Something went wrong");
      }

      setStatus("success");
      setFormData({ fullName: "", email: "", phone: "" });
    } catch (error) {
      setStatus("error");
      setErrorMessage(error.message || "Failed to subscribe. Please try again.");
    }
  };

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  if (status === "success") {
    return (
      <div className="newsletter-success">
        <div className="success-icon">✓</div>
        <p className="success-message">Welcome to the Pause Lab community!</p>
        <p className="newsletter__note">Check your email for a confirmation.</p>
      </div>
    );
  }

  return (
    <form className="newsletter-form" onSubmit={handleSubmit}>
      <div className="form-row">
        <input
          type="text"
          name="fullName"
          placeholder="Full name"
          value={formData.fullName}
          onChange={handleChange}
          required
          className="form-input"
          disabled={status === "loading"}
        />
        <input
          type="email"
          name="email"
          placeholder="Email address"
          value={formData.email}
          onChange={handleChange}
          required
          className="form-input"
          disabled={status === "loading"}
        />
        <input
          type="tel"
          name="phone"
          placeholder="Phone (e.g., +14081234567)"
          value={formData.phone}
          onChange={handleChange}
          required
          className="form-input"
          disabled={status === "loading"}
        />
      </div>
      <button
        type="submit"
        className="btn btn--white"
        disabled={status === "loading"}
      >
        {status === "loading" ? "Joining..." : "Join the Newsletter →"}
      </button>
      {status === "error" && (
        <p className="form-error">{errorMessage}</p>
      )}
      <p className="newsletter__note">Once a month. No spam. Unsubscribe anytime.</p>
    </form>
  );
}

function Nav() {
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  useEffect(() => {
    const h = () => setScrolled(window.scrollY > 50);
    window.addEventListener("scroll", h);
    return () => window.removeEventListener("scroll", h);
  }, []);
  const go = (id) => { setMenuOpen(false); document.getElementById(id)?.scrollIntoView({ behavior: "smooth" }); };
  return (
    <nav className={`nav ${scrolled ? "nav--scrolled" : ""}`}>
      <div className="nav__inner">
        <button onClick={() => go("top")} className="logo">
          <span className="logo__mark">◉</span> PAUSE
        </button>
        <div className="nav__links">
          {[["about","What We Do"],["team","Who We Are"],["book","The Book"],["newsletter","Newsletter"]].map(([id,label])=>(
            <button key={id} onClick={()=>go(id)} className="nav__link">{label}</button>
          ))}
        </div>
        <button className="hamburger" onClick={() => setMenuOpen(!menuOpen)} aria-label="Menu">
          <span className={`ham-line ${menuOpen ? "ham-line--open1" : ""}`} />
          <span className={`ham-line ${menuOpen ? "ham-line--open2" : ""}`} />
          <span className={`ham-line ${menuOpen ? "ham-line--open3" : ""}`} />
        </button>
      </div>
      {menuOpen && (
        <div className="mobile-menu">
          {[["about","What We Do"],["team","Who We Are"],["book","The Book"],["newsletter","Newsletter"]].map(([id,label])=>(
            <button key={id} onClick={()=>go(id)} className="mobile-menu__link">{label}</button>
          ))}
        </div>
      )}
    </nav>
  );
}

